<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#CDD6F4;"> task_complexity </span><span style="color:#94E2D5;">==</span><span style="color:#A6E3A1;"> &quot;simple&quot;</span><span style="color:#9399B2;">:</span></span>
